}

public class Shop : MonoBehaviour
{
    public PlayerStats playerStats;

    public void PurchaseHealthPack()
    {
        int healthPackCost = 100;
        if (playerStats.playerCurrency >= healthPackCost)
        {
            playerStats.PurchaseItem(healthPackCost);
            playerStats.playerHealth += 25;
        }
        else
        {
            Debug.Log("Not enough currency to purchase Health Pack");
        }
    }

    public void PurchaseDamageBooster()
    {
        int damageBoostCost = 200;
        if (playerStats.playerCurrency >= damageBoostCost)
        {
            playerStats.PurchaseItem(damageBoostCost);
            // Code to boost player damage
        }
        else
        {
            Debug.Log("Not enough currency to purchase Damage Booster");
        }
    }
}

public class DamageDealer : MonoBehaviour
{
    public PlayerStats playerStats;
    public int damage;

    private void OnTriggerEnter(Collider other)
    {
        if (other.gameObject.tag == "Player")
